  // ─── 17. INTRODUCTION TO ACCOUNTING (ACCOUNTING) ─────────────────────────
  "Introduction to Accounting": {
    notes: {
      body: "Accounting is the systematic process of recording, classifying, summarising, and interpreting financial transactions of a business. It provides information to owners, managers, investors, and government about the financial health of a business. The basic accounting equation and double-entry bookkeeping are the foundations of all accounting systems.",
      sections: [
        {
          title: "Basic Accounting Concepts",
          color: "#1565C0",
          items: [
            "Assets – resources owned by a business (e.g. cash, buildings, equipment, stock)",
            "Liabilities – amounts owed by the business to others (e.g. loans, creditors)",
            "Capital (Owner's Equity) – the owner's investment in the business; Assets – Liabilities = Capital",
            "Revenue (Income) – money earned from selling goods or services",
            "Expenses – costs incurred in running the business (e.g. rent, wages, electricity)",
            "Profit = Revenue – Expenses (when revenue exceeds expenses)",
            "Loss = Expenses – Revenue (when expenses exceed revenue)"
          ]
        },
        {
          title: "Double-Entry Bookkeeping",
          color: "#6A1B9A",
          items: [
            "Every transaction affects at least two accounts (debit and credit)",
            "Debit (Dr) – left side of an account; increases assets and expenses",
            "Credit (Cr) – right side of an account; increases liabilities, capital, and revenue",
            "The accounting equation must always balance: Assets = Liabilities + Capital",
            "Ledger – the book containing all accounts of a business",
            "Trial balance – a list of all debit and credit balances to check that they are equal",
            "Journal – the book of original entry where transactions are first recorded"
          ]
        },
        {
          title: "Financial Statements",
          color: "#00695C",
          items: [
            "Income Statement (Profit & Loss Account) – shows revenue, expenses, and profit/loss for a period",
            "Balance Sheet – shows assets, liabilities, and capital at a specific date",
            "Cash Flow Statement – shows cash inflows and outflows",
            "Trading Account – shows gross profit (Sales – Cost of Goods Sold)",
            "Gross Profit = Sales Revenue – Cost of Goods Sold (COGS)",
            "Net Profit = Gross Profit – Operating Expenses",
            "The balance sheet must always balance: Assets = Liabilities + Capital"
          ]
        }
      ],
      definition: "Accounting is the systematic process of recording, classifying, summarising, and interpreting financial transactions to provide useful information for decision-making.",
      formula: "Accounting Equation: Assets = Liabilities + Capital | Profit = Revenue – Expenses | Gross Profit = Sales – Cost of Goods Sold",
      example: "A shop buys goods worth SSP 500 on credit. Assets (stock) increase by SSP 500; Liabilities (creditors) increase by SSP 500. The accounting equation remains balanced: Assets = Liabilities + Capital.",
      summary: "Accounting records financial transactions using the double-entry system. The accounting equation (Assets = Liabilities + Capital) must always balance. Key financial statements include the Income Statement and Balance Sheet."
    },
    qa: [
      { q: "What is accounting?", a: "Accounting is the systematic process of recording, classifying, summarising, and interpreting financial transactions of a business to provide useful information for decision-making by owners, managers, and other stakeholders." },
      { q: "State the basic accounting equation.", a: "The basic accounting equation is: Assets = Liabilities + Capital. This equation must always balance because every transaction has a dual effect on the accounts." },
      { q: "What are assets? Give three examples.", a: "Assets are resources owned by a business that have economic value. Examples: cash, bank balance, buildings, equipment, motor vehicles, stock (inventory), and debtors (money owed to the business)." },
      { q: "What are liabilities? Give two examples.", a: "Liabilities are amounts owed by the business to external parties. Examples: bank loans, creditors (suppliers owed money), overdrafts, and mortgages." },
      { q: "What is capital in accounting?", a: "Capital (also called owner's equity) is the owner's investment in the business. It equals Assets minus Liabilities. It increases when the owner invests more money or when the business makes a profit." },
      { q: "What is the difference between revenue and profit?", a: "Revenue (income) is the total money earned from selling goods or services. Profit is what remains after all expenses are deducted from revenue. Profit = Revenue – Expenses." },
      { q: "What is double-entry bookkeeping?", a: "Double-entry bookkeeping is the system where every financial transaction is recorded in at least two accounts – one account is debited and another is credited by the same amount. This ensures the accounting equation always balances." },
      { q: "What is a trial balance?", a: "A trial balance is a list of all debit and credit balances from the ledger accounts at a specific date. It is used to check that total debits equal total credits, confirming the accuracy of the bookkeeping." },
      { q: "What is gross profit and how is it calculated?", a: "Gross profit is the profit made from buying and selling goods before deducting operating expenses. Gross Profit = Sales Revenue – Cost of Goods Sold (COGS)." },
      { q: "What is the difference between a balance sheet and an income statement?", a: "An income statement (profit and loss account) shows revenue, expenses, and profit or loss over a period of time. A balance sheet shows the financial position of a business at a specific date, listing assets, liabilities, and capital." }
    ],
    quiz: [
      { q: "The basic accounting equation is:", options: ["Assets = Revenue – Expenses", "Assets = Liabilities + Capital", "Capital = Assets + Liabilities", "Profit = Assets – Liabilities"], answer: 1 },
      { q: "Assets are:", options: ["Amounts owed by the business", "Resources owned by the business", "The owner's investment", "Money earned from sales"], answer: 1 },
      { q: "Liabilities are:", options: ["Resources owned by the business", "The owner's investment", "Amounts owed by the business to others", "Profit made by the business"], answer: 2 },
      { q: "Gross Profit is calculated as:", options: ["Sales – Operating Expenses", "Sales – Cost of Goods Sold", "Revenue – Capital", "Assets – Liabilities"], answer: 1 },
      { q: "In double-entry bookkeeping, every transaction affects:", options: ["One account only", "At least two accounts", "Three accounts always", "The balance sheet only"], answer: 1 },
      { q: "A trial balance is used to:", options: ["Calculate profit", "Check that total debits equal total credits", "List all assets", "Prepare a cash flow statement"], answer: 1 },
      { q: "The Income Statement shows:", options: ["Assets and liabilities at a specific date", "Revenue, expenses, and profit/loss over a period", "Cash inflows and outflows only", "The owner's capital only"], answer: 1 },
      { q: "Capital equals:", options: ["Assets + Liabilities", "Assets – Liabilities", "Revenue – Expenses", "Liabilities – Assets"], answer: 1 },
      { q: "Which of these is a LIABILITY?", options: ["Cash in hand", "Motor vehicle", "Bank loan", "Stock of goods"], answer: 2 },
      { q: "Net Profit is calculated as:", options: ["Sales – Cost of Goods Sold", "Gross Profit – Operating Expenses", "Revenue + Expenses", "Assets – Capital"], answer: 1 }
    ]
  },

